                                 <summary className="cursor-pointer font-bold">Ver erro técnico do Google</summary>
                                 <pre className="mt-1 p-2 bg-black/50 rounded overflow-x-auto text-[9px] font-mono whitespace-pre-wrap">
                                     {newsError}
                                 </pre>
