                     <button onClick={() => handleNavigation(ViewState.GOOGLE)} className="mt-3 text-xs bg-blue-600/20 text-blue-300 px-3 py-1.5 rounded-full font-bold border border-blue-600/30">
                        Ir para Login
                     </button>
                 )}
             </div>
