  const fetchTrelloCards = async () => {
    if (!trelloKey || !trelloToken || !trelloListIds.length) return;
    setIsLoadingTrello(true);
    try {
      let currentLists = availableLists;
      if (availableLists.length === 0 && trelloBoardId) {
