import { NewsArticle } from "../types";

// Fallback final caso até o RSS falhe
const generateOfflineCards = (topics: string[]): NewsArticle[] => {
    return topics.map((t, i) => ({
        id: `offline-${Date.now()}-${i}`,
        topic: t,
        title: `Ver notícias sobre ${t}`,
        summary: 'Toque para buscar no Google.',
        source: 'Google Search',
        publishedAt: 'Agora',
        url: `https://www.google.com/search?q=${encodeURIComponent(t + " notícias")}`
    }));
};

/**
 * Busca notícias reais usando RSS do Google News via Proxy (para evitar CORS).
 * Isso é muito mais estável em mobile do que a ferramenta de Search da IA.
 */
export const fetchNewsWithAI = async (topics: string[], apiKeyOverride?: string): Promise<NewsArticle[]> => {
  // Nota: apiKeyOverride é ignorado aqui pois mudamos para RSS público, 
  // mas mantemos a assinatura da função para compatibilidade.

  const articles: NewsArticle[] = [];

  // Seleciona aleatoriamente 3 tópicos para buscar a cada vez para economizar dados e variar o conteúdo
  const shuffledTopics = [...topics].sort(() => 0.5 - Math.random()).slice(0, 3);

  const fetchPromises = shuffledTopics.map(async (topic) => {
      try {
          // Google News RSS URL (PT-BR)
          const rssUrl = `https://news.google.com/rss/search?q=${encodeURIComponent(topic + " when:2d")}&hl=pt-BR&gl=BR&ceid=BR:pt-419`;

          // Proxy para contornar CORS no navegador/celular
          const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(rssUrl)}`;

          const response = await fetch(proxyUrl);
          if (!response.ok) return null;

          const data = await response.json();
          const xmlString = data.contents;

          // Parse simples do XML
          const parser = new DOMParser();
          const xmlDoc = parser.parseFromString(xmlString, "text/xml");
          const items = xmlDoc.querySelectorAll("item");

          if (items.length > 0) {
              // Pega a notícia mais relevante do tópico
              const item = items[0];
              const titleFull = item.querySelector("title")?.textContent || "";
              const link = item.querySelector("link")?.textContent || "";
              const pubDateRaw = item.querySelector("pubDate")?.textContent || "";
              const sourceRaw = item.querySelector("source")?.textContent || "Google News";

              // Limpeza do Título (Geralmente vem "Titulo - Fonte")
              const titleParts = titleFull.split(" - ");
              const title = titleParts.length > 1 ? titleParts.slice(0, -1).join(" - ") : titleFull;

              // Formata Data
              const pubDate = new Date(pubDateRaw);
              const timeString = isNaN(pubDate.getTime()) 
                  ? "Recente" 
                  : pubDate.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

              return {
                  id: `news-${topic}-${Date.now()}`,
                  topic: topic,
                  title: title,
                  summary: titleFull, // RSS não tem summary bom, usamos o título completo
                  source: sourceRaw,
                  publishedAt: timeString,
                  url: link
              } as NewsArticle;
          }
      } catch (e) {
          console.warn(`Falha ao buscar RSS para ${topic}`, e);
          return null;
      }
      return null;
  });

  const results = await Promise.all(fetchPromises);
  const validArticles = results.filter((a): a is NewsArticle => a !== null);

  if (validArticles.length === 0) {
      return generateOfflineCards(topics.slice(0, 3));
  }

  return validArticles;
};

