/**
 * Busca notícias usando RSS do Google News via Proxy RAW.
 * Usamos 'api.allorigins.win/raw' para obter o XML direto, o que é mais robusto.
 */
export const fetchNewsWithAI = async (topics: string[], apiKeyOverride?: string): Promise<NewsArticle[]> => {
  const articles: NewsArticle[] = [];

  // Seleciona aleatoriamente 3 tópicos
  const shuffledTopics = [...topics].sort(() => 0.5 - Math.random()).slice(0, 3);

  const fetchPromises = shuffledTopics.map(async (topic) => {
      try {
          // Removemos 'when:2d' para garantir resultados sempre
          const rssUrl = `https://news.google.com/rss/search?q=${encodeURIComponent(topic)}&hl=pt-BR&gl=BR&ceid=BR:pt-419`;

          // Usamos /raw para receber o XML diretamente, evitando problemas de parse de JSON
          const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(rssUrl)}`;

          const response = await fetch(proxyUrl);
          if (!response.ok) throw new Error("Network response was not ok");

          const xmlString = await response.text();

          // Verificação básica se é XML válido e não uma página de erro HTML
          if (xmlString.trim().startsWith("<!DOCTYPE html>") || xmlString.includes("403 Forbidden")) {
             throw new Error("Proxy blocked or returned HTML");
          }

          const parser = new DOMParser();
          const xmlDoc = parser.parseFromString(xmlString, "text/xml");
          const items = xmlDoc.querySelectorAll("item");

          if (items.length > 0) {
              const item = items[0]; // Pega a primeira notícia

              const titleFull = item.querySelector("title")?.textContent || "";

              // Limpeza do HTML no description se houver (RSS do Google as vezes manda HTML)
              let description = item.querySelector("description")?.textContent || titleFull;
              // Remove tags HTML simples para ficar limpo no card
              description = description.replace(/<[^>]*>?/gm, '');
              // Se a descrição for muito curta ou duplicada do título, usa o título
              if (description.length < 10 || description === titleFull) {
                  description = titleFull;
              }

              const link = item.querySelector("link")?.textContent || "";
              const pubDateRaw = item.querySelector("pubDate")?.textContent || "";
              const sourceRaw = item.querySelector("source")?.textContent || "Google News";

              // Limpeza do Título (Remove o nome da fonte no final " - G1")
              const titleParts = titleFull.split(" - ");
              const title = titleParts.length > 1 ? titleParts.slice(0, -1).join(" - ") : titleFull;

              const pubDate = new Date(pubDateRaw);
              const timeString = isNaN(pubDate.getTime()) 
                  ? "Recente" 
                  : pubDate.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }) + ' ' + pubDate.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

              return {
                  id: `news-${topic}-${Date.now()}`,
                  topic: topic,
                  title: title,
                  summary: titleFull, // Usamos o título completo como resumo visual
                  source: sourceRaw,
                  publishedAt: timeString,
                  url: link
              } as NewsArticle;
          }
      } catch (e) {
          console.warn(`Erro RSS para ${topic}:`, e);
          return null;
      }
      return null;
  });

  const results = await Promise.all(fetchPromises);
  const validArticles = results.filter((a): a is NewsArticle => a !== null);

  // Se falhar tudo, retorna o fallback
  if (validArticles.length === 0) {
      return generateOfflineCards(topics.slice(0, 3));
  }

  return validArticles;
};

