export const fetchNewsWithAI = async (topics: string[], apiKeyOverride?: string): Promise<NewsArticle[]> => {
  // Aumentamos o limite de tópicos para buscar (até 5 tópicos diferentes)
  const shuffledTopics = [...topics].sort(() => 0.5 - Math.random()).slice(0, 5);

  const fetchPromises = shuffledTopics.map(async (topic) => {
      try {
          // --- TENTATIVA 1: Google News RSS ---
          const googleUrl = `https://news.google.com/rss/search?q=${encodeURIComponent(topic)}&hl=pt-BR&gl=BR&ceid=BR:pt-419`;
          let xmlString = "";
          let provider = "google";

          try {
              xmlString = await fetchWithProxy(googleUrl);
          } catch (e) {
              console.warn(`Google News falhou para ${topic}, tentando Bing...`);
              // --- TENTATIVA 2: Bing News RSS (Fallback se Google bloquear) ---
              const bingUrl = `https://www.bing.com/news/search?q=${encodeURIComponent(topic)}&format=rss`;
              xmlString = await fetchWithProxy(bingUrl);
              provider = "bing";
          }

          // Parse XML
          const parser = new DOMParser();
          const xmlDoc = parser.parseFromString(xmlString, "text/xml");
          const items = xmlDoc.querySelectorAll("item");

          if (items.length > 0) {
              // PEGAR AS 3 PRIMEIRAS NOTÍCIAS DE CADA TÓPICO
              const topItems = Array.from(items).slice(0, 3);

              return topItems.map((item, index) => {
                  const titleFull = item.querySelector("title")?.textContent || "";
                  let link = item.querySelector("link")?.textContent || "";

                  if (provider === "bing" && !link.startsWith("http")) {
                       const guid = item.querySelector("guid")?.textContent;
                       if (guid && guid.startsWith("http")) link = guid;
                  }

                  const pubDateRaw = item.querySelector("pubDate")?.textContent || "";
                  const sourceRaw = item.querySelector("source")?.textContent || (provider === "bing" ? "Bing News" : "Google News");

                  // Limpeza do Título
                  const titleParts = titleFull.split(" - ");
                  const title = titleParts.length > 1 ? titleParts.slice(0, -1).join(" - ") : titleFull;

                  const pubDate = new Date(pubDateRaw);

                  // Lógica robusta de Timestamp: Se a data for inválida, gera uma data aleatória nas últimas 24h
                  // Isso garante que notícias sem data não fiquem todas agrupadas no final
                  let timestamp = pubDate.getTime();
                  if (isNaN(timestamp)) {
                      timestamp = Date.now() - Math.floor(Math.random() * 86400000); 
                  }

                  const timeString = isNaN(pubDate.getTime()) 
                      ? "Recente" 
                      : pubDate.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }) + ' ' + pubDate.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

                  return {
                      id: `news-${topic}-${Date.now()}-${index}`, // ID único com index
                      topic: topic,
                      title: title,
                      summary: titleFull, 
                      source: sourceRaw,
                      publishedAt: timeString,
                      timestamp: timestamp, // Usado para ordenação
                      url: link
                  } as NewsArticle;
              });
          }
      } catch (e) {
          console.warn(`Erro total ao buscar notícia para ${topic}:`, e);
          return null;
      }
      return null;
  });

  const results = await Promise.all(fetchPromises);

  // Flatten array de arrays
  const validArticles = results
      .flat()
      .filter((a): a is NewsArticle => a !== null && a !== undefined);

  // Remove duplicatas baseadas no título (caso tópicos se sobreponham)
  const uniqueArticles = Array.from(new Map(validArticles.map(item => [item.title, item])).values());

  if (uniqueArticles.length === 0) {
      return generateOfflineCards(topics.slice(0, 3));
  }

  // ORDENAÇÃO: Mais recentes primeiro (Decrescente)
  // Isso mistura os tópicos naturalmente, pois a ordem será baseada na hora da publicação e não no tópico.
  uniqueArticles.sort((a, b) => b.timestamp - a.timestamp);

  return uniqueArticles;
};

import { GoogleGenAI } from "@google/genai";
import { FormSubmission } from "../types";
import { FALLBACK_API_KEY } from "../constants";

// Função auxiliar para garantir que temos uma chave
const getApiKey = (): string | undefined => {
  // Prioriza a variável de ambiente (Web), mas usa o fallback do constants.ts (Mobile/PWA)
  let key = process.env.API_KEY;

  if (!key || key.trim() === '') {
      key = FALLBACK_API_KEY;
  }

  return (key && key.trim() !== '') ? key : undefined;
};

export const analyzeForms = async (forms: FormSubmission[]): Promise<string> => {
  try {
    const apiKey = getApiKey();
    if (!apiKey) return "Erro: Configure FALLBACK_API_KEY no constants.ts";

    const ai = new GoogleGenAI({ apiKey });

    const formSummary = forms.map(f => 
      `- De: ${f.senderName} (${f.senderEmail}) | Mensagem: "${f.message}" | Data: ${f.timestamp.toLocaleString()}`
    ).join('\n');

    const prompt = `
      Analise estas mensagens de formulário de contato:
      ${formSummary}

      Resuma a oportunidade mais urgente e o sentimento geral em português.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    return response.text || "Análise indisponível.";
  } catch (error: any) {
    console.error("Erro Gemini Forms:", error);
    return `Erro: ${error.message || 'Falha na IA'}`;
  }
};

export const generateDashboardInsight = async (context: {
    sites: string[],
    forms: string[],
    emails: string[],
    trello: number,
    weather?: string
}, apiKeyOverride?: string): Promise<string> => {

    // Tenta usar a chave passada por parâmetro (do ConfigModal), se não, usa a do ambiente/fallback
    const apiKey = (apiKeyOverride && apiKeyOverride.trim() !== '') ? apiKeyOverride : getApiKey();

    if (!apiKey) {
        throw new Error("API Key ausente. Configure nas Engrenagem > Credenciais.");
    }

    try {
        const ai = new GoogleGenAI({ apiKey });

        const siteText = context.sites?.length ? context.sites.join(', ') : "Todos online.";
        const formText = context.forms?.length ? context.forms.join('; ') : "Sem mensagens.";
        const emailText = context.emails?.length ? context.emails.join('; ') : "Sem urgências.";
        const trelloText = context.trello > 0 ? `${context.trello} tarefas.` : "Trello em dia.";
        const weatherText = context.weather || "Clima desconhecido.";

        const prompt = `
        Atue como assistente pessoal (Tidas).
        DADOS:
        - Clima: ${weatherText}
        - Sites: ${siteText}
        - Inbox: ${formText} // ${emailText}
        - Trello: ${trelloText}

        INSTRUÇÃO:
        Crie um resumo executivo de 3 linhas em Português.
        Considere a previsão do tempo para a semana ao dar conselhos.
        Se houver chuva ou site offline, priorize isso.
        Seja direto.
        `;

        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
        });

        if (!response.text) {
            throw new Error("IA retornou vazio.");
        }

        return response.text;
    } catch (error: any) {
        console.error("Erro detalhado Insight:", error);

        let message = error.message || error.toString();

        if (message.includes("API key") || message.includes("403")) {
            throw new Error("Chave API recusada. Verifique as configurações.");
        }
        if (message.includes("fetch")) {
             throw new Error("Sem internet.");
        }
        if (message.includes("quota")) {
             throw new Error("Cota excedida (429).");
        }
        throw new Error("Erro na IA: " + message.substring(0, 30));
    }
}

