      console.error("Erro Google:", error);
      if (error.message === 'API_NOT_ENABLED') {
        setApiNotEnabled(true);
      } else if (error.message === 'AUTH_EXPIRED') {
        console.warn("Token expirado");
      }
    } finally {
      setIsLoadingGoogle(false);
