                  {!isLoadingNews && !newsError && newsArticles.length === 0 && (
                      <div className="bg-slate-800 p-6 rounded-xl border border-slate-700 text-center">
                          <Newspaper className="w-10 h-10 text-slate-600 mx-auto mb-3" />
