             <button onClick={() => setIsConfigModalOpen(true)} className="p-2 -mr-2 text-slate-400 hover:text-white rounded-full hover:bg-slate-800 transition-colors"><Settings className="w-6 h-6" /></button>
         </div>
      </header>

