        className="max-w-md mx-auto min-h-screen relative pt-[calc(4rem+env(safe-area-inset-top,20px))] px-4 pb-safe-area"
        onTouchStart={handleTouchStart}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleTouchEnd}
      >
